@dataclass
class AppRoleSecretID:
    """Secret ID generated for an AppRole."""

    role_name: str
    secret_id: str = field(repr=False)
    accessor: str
    metadata: dict[str, str] = field(default_factory=dict)
    ttl: float = 0.0
    num_uses: int = 0
    uses_remaining: int = 0
    created_at: float = field(default_factory=time.time)
    disabled: bool = False

    def __post_init__(self) -> None:
        if self.num_uses > 0 and self.uses_remaining == 0:
            self.uses_remaining = self.num_uses

    @property
    def is_expired(self) -> bool:
        return self.ttl > 0 and time.time() >= self.created_at + self.ttl

    @property
    def is_valid(self) -> bool:
        if self.disabled or self.is_expired:
            return False
        return self.num_uses <= 0 or self.uses_remaining > 0

    def use(self) -> None:
        if self.num_uses > 0:
            if self.uses_remaining <= 0:
                raise AuthenticationError("secret_id has no remaining uses")
            self.uses_remaining -= 1

    def to_dict(self) -> dict[str, Any]:
        return {
            "role_name": self.role_name,
            "accessor": self.accessor,
            "metadata": dict(self.metadata),
            "ttl": self.ttl,
            "num_uses": self.num_uses,
            "uses_remaining": self.uses_remaining,
            "created_at": self.created_at,
            "disabled": self.disabled,
        }


class AppRoleAuthBackend(AuthBackend):
    """AppRole authentication using generated role IDs and secret IDs."""

    def __init__(self, name: str = "approle", enabled: bool = True) -> None:
        super().__init__(name=name, enabled=enabled)
        self._roles: dict[str, AppRole] = {}
        self._role_id_index: dict[str, str] = {}
        self._secret_ids: dict[str, dict[str, AppRoleSecretID]] = {}

    def create_role(
        self,
        role_name: str,
        policies: list[str] | None = None,
        metadata: dict[str, str] | None = None,
        token_ttl: float = 3600.0,
        secret_id_ttl: float = 0.0,
        secret_id_num_uses: int = 0,
        role_id: str | None = None,
        disabled: bool = False,
    ) -> AppRole:
        if not role_name:
            raise VaultError("role name is required")
        if role_name in self._roles:
            raise VaultError(f"role already exists: {role_name}")
        if secret_id_num_uses < 0:
            raise VaultError("secret_id_num_uses must be non-negative")
        generated_role_id = role_id or generate_id("role", 24)
        if generated_role_id in self._role_id_index:
            raise VaultError("role_id already exists")

        role = AppRole(
            role_name=role_name,
            role_id=generated_role_id,
            policies=list(policies or []),
            metadata=dict(metadata or {}),
            token_ttl=token_ttl,
            secret_id_ttl=secret_id_ttl,
            secret_id_num_uses=secret_id_num_uses,
            disabled=disabled,
        )
        self._roles[role_name] = role
        self._role_id_index[generated_role_id] = role_name
        self._secret_ids[role_name] = {}
        return role

    def get_role(self, role_name: str) -> AppRole | None:
        return self._roles.get(role_name)

    def delete_role(self, role_name: str) -> bool:
        role = self._roles.pop(role_name, None)
        if role is None:
            return False
        self._role_id_index.pop(role.role_id, None)
        self._secret_ids.pop(role_name, None)
        return True

    def list_roles(self) -> list[str]:
        return sorted(self._roles)

    def disable_role(self, role_name: str) -> bool:
        role = self._roles.get(role_name)
        if role is None:
            return False
        role.disabled = True
        role.updated_at = time.time()
        return True

    def enable_role(self, role_name: str) -> bool:
        role = self._roles.get(role_name)
        if role is None:
            return False
        role.disabled = False
        role.updated_at = time.time()
        return True

    def generate_secret_id(
        self,
        role_name: str,
        metadata: dict[str, str] | None = None,
        ttl: float | None = None,
        num_uses: int | None = None,
    ) -> AppRoleSecretID:
        role = self._roles.get(role_name)
        if role is None:
            raise VaultError(f"role not found: {role_name}")
        if num_uses is not None and num_uses < 0:
            raise VaultError("num_uses must be non-negative")

        secret = AppRoleSecretID(
            role_name=role_name,
            secret_id=generate_token(32),
            accessor=generate_id("sid", 12),
            metadata=dict(metadata or {}),
            ttl=role.secret_id_ttl if ttl is None else ttl,
            num_uses=role.secret_id_num_uses if num_uses is None else num_uses,
        )
        self._secret_ids.setdefault(role_name, {})[secret.accessor] = secret
        return secret

    def revoke_secret_id(self, role_name: str, accessor: str) -> bool:
        return self._secret_ids.get(role_name, {}).pop(accessor, None) is not None

    def list_secret_id_accessors(self, role_name: str) -> list[str]:
        return sorted(self._secret_ids.get(role_name, {}))

    def authenticate(self, **credentials: Any) -> AuthResult:
        self._require_enabled()
        role_id = credentials.get("role_id")
        secret_id = credentials.get("secret_id")
        if not isinstance(role_id, str) or not isinstance(secret_id, str):
            raise AuthenticationError("role_id and secret_id are required")

        role_name = self._role_id_index.get(role_id)
        if role_name is None:
            raise AuthenticationError("invalid role_id or secret_id")
        role = self._roles[role_name]
        if role.disabled:
            raise AuthenticationError("role is disabled", details={"role_name": role_name})

        secret = self._find_secret_id(role_name, secret_id)
        if secret is None or not secret.is_valid:
            raise AuthenticationError("invalid role_id or secret_id")
        secret.use()

        metadata = dict(role.metadata)
        metadata.update(secret.metadata)
        metadata["role_name"] = role.role_name
        metadata["role_id"] = role.role_id
        metadata["secret_id_accessor"] = secret.accessor
        return AuthResult(
            backend=self.name,
            identity=role.role_name,
            policies=list(role.policies),
            metadata=metadata,
            ttl=role.token_ttl,
        )

    def _find_secret_id(self, role_name: str, secret_id: str) -> AppRoleSecretID | None:
        needle = secret_id.encode("utf-8")
        for secret in self._secret_ids.get(role_name, {}).values():
            if constant_time_compare(needle, secret.secret_id.encode("utf-8")):
                return secret
        return None


@dataclass
class CertificateCredential:
    """Registered certificate fingerprint credential."""

    name: str
    fingerprint: str
    policies: list[str] = field(default_factory=list)
    metadata: dict[str, str] = field(default_factory=dict)
    ttl: float = 3600.0
    disabled: bool = False
    created_at: float = field(default_factory=time.time)
    updated_at: float = field(default_factory=time.time)

    def to_dict(self) -> dict[str, Any]:
        return {
            "name": self.name,
            "fingerprint": self.fingerprint,
            "policies": list(self.policies),
            "metadata": dict(self.metadata),
            "ttl": self.ttl,
            "disabled": self.disabled,
        }


class CertificateAuthBackend(AuthBackend):
    """Certificate fingerprint authentication."""

    def __init__(self, name: str = "cert", enabled: bool = True) -> None:
        super().__init__(name=name, enabled=enabled)
        self._certificates: dict[str, CertificateCredential] = {}
        self._fingerprint_index: dict[str, str] = {}

    def register_certificate(
        self,
        name: str,
        fingerprint: str,
        policies: list[str] | None = None,
        metadata: dict[str, str] | None = None,
        ttl: float = 3600.0,
        disabled: bool = False,
    ) -> CertificateCredential:
        if not name:
            raise VaultError("certificate name is required")
        if name in self._certificates:
            raise VaultError(f"certificate already exists: {name}")
        normalized = normalize_fingerprint(fingerprint)
        if normalized in self._fingerprint_index:
            raise VaultError("certificate fingerprint already exists")

        certificate = CertificateCredential(
            name=name,
            fingerprint=normalized,
            policies=list(policies or []),
            metadata=dict(metadata or {}),
            ttl=ttl,
            disabled=disabled,
        )
        self._certificates[name] = certificate
        self._fingerprint_index[normalized] = name
        return certificate

    def get_certificate(self, name: str) -> CertificateCredential | None:
        return self._certificates.get(name)

    def delete_certificate(self, name: str) -> bool:
        certificate = self._certificates.pop(name, None)
        if certificate is None:
            return False
        self._fingerprint_index.pop(certificate.fingerprint, None)
        return True

    def list_certificates(self) -> list[str]:
        return sorted(self._certificates)

    def disable_certificate(self, name: str) -> bool:
        certificate = self._certificates.get(name)
        if certificate is None:
            return False
        certificate.disabled = True
        certificate.updated_at = time.time()
        return True

    def enable_certificate(self, name: str) -> bool:
        certificate = self._certificates.get(name)
        if certificate is None:
            return False
        certificate.disabled = False
        certificate.updated_at = time.time()
        return True

    def authenticate(self, **credentials: Any) -> AuthResult:
        self._require_enabled()
        fingerprint = credentials.get("fingerprint")
        certificate = credentials.get("certificate")
        if isinstance(fingerprint, str):
            normalized = normalize_fingerprint(fingerprint)
        elif isinstance(certificate, (bytes, str)):
            normalized = fingerprint_certificate(certificate)
        else:
            raise AuthenticationError("certificate fingerprint is required")

        credential = self._find_certificate(normalized)
        if credential is None:
            raise AuthenticationError("invalid certificate fingerprint")
        if credential.disabled:
            raise AuthenticationError(
                "certificate is disabled",
                details={"certificate": credential.name},
            )

        return AuthResult(
            backend=self.name,
            identity=credential.name,
            policies=list(credential.policies),
            metadata=dict(credential.metadata),
            ttl=credential.ttl,
        )

    def _find_certificate(self, normalized: str) -> CertificateCredential | None:
        needle = normalized.encode("utf-8")
        for stored, name in self._fingerprint_index.items():
            if constant_time_compare(needle, stored.encode("utf-8")):
                return self._certificates[name]
        return None


class TokenAuthBackend(AuthBackend):
    """Validate already-issued VaultKey tokens."""

    def __init__(
        self,
        token_store: TokenStore | None = None,
        name: str = "token",
        enabled: bool = True,
    ) -> None:
        super().__init__(name=name, enabled=enabled)
        self.token_store = token_store or TokenStore()

    def authenticate(self, **credentials: Any) -> AuthResult:
        self._require_enabled()
        token_id = credentials.get("token") or credentials.get("token_id")
        accessor = credentials.get("accessor")
        if isinstance(token_id, str):
            token = self._lookup_token(token_id)
        elif isinstance(accessor, str):
            token = self._lookup_accessor(accessor)
        else:
            raise AuthenticationError("token is required")

        try:
            token.use()
        except TokenError as exc:
            raise AuthenticationError("invalid token", details={"reason": exc.message}) from exc

        ttl = token.remaining_ttl
        return AuthResult(
            backend=self.name,
            identity=token.entity_id or token.accessor,
            policies=list(token.policies),
            metadata=dict(token.metadata),
            ttl=ttl,
            renewable=token.renewable,
            token=token.token_id,
            accessor=token.accessor,
            entity_id=token.entity_id,
        )

    def _lookup_token(self, token_id: str) -> Token:
        try:
            return self.token_store.lookup(token_id)
        except TokenError as exc:
            raise AuthenticationError("invalid token", details={"reason": exc.message}) from exc

    def _lookup_accessor(self, accessor: str) -> Token:
        try:
            return self.token_store.lookup_accessor(accessor)
        except TokenError as exc:
            raise AuthenticationError("invalid token", details={"reason": exc.message}) from exc


class AuthManager:
    """Registers auth backends by name and dispatches authentication requests."""

    def __init__(self, backends: dict[str, AuthBackend] | None = None) -> None:
        self._backends: dict[str, AuthBackend] = {}
        for name, backend in (backends or {}).items():
            self.register_backend(name, backend)

    def register_backend(self, name: str, backend: AuthBackend) -> None:
        if not name:
            raise VaultError("backend name is required")
        self._backends[name] = backend

    def register(self, backend: AuthBackend, name: str | None = None) -> None:
        self.register_backend(name or backend.name, backend)

    def get_backend(self, name: str) -> AuthBackend | None:
        return self._backends.get(name)

    def list_backends(self) -> list[str]:
        return sorted(self._backends)

    def enable_backend(self, name: str) -> None:
        backend = self._backends.get(name)
        if backend is None:
            raise AuthenticationError("unknown auth backend", details={"backend": name})
        backend.enable()

    def disable_backend(self, name: str) -> None:
        backend = self._backends.get(name)
        if backend is None:
            raise AuthenticationError("unknown auth backend", details={"backend": name})
        backend.disable()

    def authenticate(self, backend_name: str, **credentials: Any) -> AuthResult:
        backend = self._backends.get(backend_name)
        if backend is None:
            raise AuthenticationError(
                "unknown auth backend",
                details={"backend": backend_name},
            )
        if not backend.enabled:
            raise AuthenticationError(
                f"auth backend is disabled: {backend_name}",
                details={"backend": backend_name},
            )
        return backend.authenticate(**credentials)


@dataclass
class RateLimitState:
    """Observable rate-limit state for a single attempt key."""

    key: str
    attempts: int
    remaining_attempts: int
    locked_until: float = 0.0
    limited: bool = False


class AuthRateLimiter:
    """In-memory fixed-window rate limiter for auth attempts."""

    def __init__(
        self,
        max_attempts: int = 5,
        window: float = 60.0,
        lockout: float = 300.0,
    ) -> None:
        if max_attempts <= 0:
            raise VaultError("max_attempts must be positive")
        if window <= 0 or lockout < 0:
            raise VaultError("window must be positive and lockout must be non-negative")
        self.max_attempts = max_attempts
        self.window = window
        self.lockout = lockout
        self._attempts: dict[str, list[float]] = {}
        self._locked_until: dict[str, float] = {}

    def require_allowed(self, key: str, now: float | None = None) -> None:
        if self.is_limited(key, now=now):
            state = self.get_state(key, now=now)
            raise AuthenticationError(
                "too many authentication attempts",
                details={"key": key, "locked_until": state.locked_until},
            )

    def is_limited(self, key: str, now: float | None = None) -> bool:
        state = self.get_state(key, now=now)
        return state.limited

    def record_attempt(
        self,
        key: str,
        success: bool,
        now: float | None = None,
    ) -> RateLimitState:
        if not key:
            raise AuthenticationError("rate limit key is required")
        current_time = time.time() if now is None else now
        if success:
            self.reset(key)
            return self.get_state(key, now=current_time)
        if self.is_limited(key, now=current_time):
            return self.get_state(key, now=current_time)

        attempts = self._attempts.setdefault(key, [])
        attempts.append(current_time)
        self._prune(key, current_time)
        if len(self._attempts.get(key, [])) >= self.max_attempts:
            self._locked_until[key] = current_time + self.lockout
        return self.get_state(key, now=current_time)

    def get_state(self, key: str, now: float | None = None) -> RateLimitState:
        if not key:
            raise AuthenticationError("rate limit key is required")
        current_time = time.time() if now is None else now
        self._prune(key, current_time)
        attempts = len(self._attempts.get(key, []))
        locked_until = self._locked_until.get(key, 0.0)
        limited = locked_until > current_time
        return RateLimitState(
            key=key,
            attempts=attempts,
            remaining_attempts=max(0, self.max_attempts - attempts),
            locked_until=locked_until if limited else 0.0,
            limited=limited,
        )

    def reset(self, key: str) -> None:
        self._attempts.pop(key, None)
        self._locked_until.pop(key, None)

    def _prune(self, key: str, now: float) -> None:
        locked_until = self._locked_until.get(key)
        if locked_until is not None and locked_until <= now:
            self._locked_until.pop(key, None)
            self._attempts.pop(key, None)
            return
        threshold = now - self.window
        self._attempts[key] = [
            timestamp for timestamp in self._attempts.get(key, [])
            if timestamp >= threshold
        ]
        if not self._attempts[key]:
            self._attempts.pop(key, None)


@dataclass
class AuthSession:
    """In-memory authenticated session."""

    session_id: str
    backend: str
    identity: str
    policies: list[str] = field(default_factory=list)
    metadata: dict[str, str] = field(default_factory=dict)
    ttl: float = 3600.0
    created_at: float = field(default_factory=time.time)
    last_active: float = field(default_factory=time.time)
    expires_at: float = 0.0
    revoked: bool = False

    def __post_init__(self) -> None:
        if self.expires_at == 0.0 and self.ttl > 0 and not math.isinf(self.ttl):
            self.expires_at = self.created_at + self.ttl

    @property
    def is_expired(self) -> bool:
        return self.expires_at > 0 and time.time() >= self.expires_at

    @property
    def is_valid(self) -> bool:
        return not self.revoked and not self.is_expired

    def is_valid_at(self, now: float) -> bool:
        expired = self.expires_at > 0 and now >= self.expires_at
        return not self.revoked and not expired

    def touch(self, now: float | None = None) -> None:
        self.last_active = time.time() if now is None else now

    def revoke(self) -> None:
        self.revoked = True

    def to_dict(self) -> dict[str, Any]:
        return {
            "session_id": self.session_id,
            "backend": self.backend,
            "identity": self.identity,
            "policies": list(self.policies),
            "metadata": dict(self.metadata),
            "ttl": self.ttl,
            "created_at": self.created_at,
            "last_active": self.last_active,
            "expires_at": self.expires_at,
            "revoked": self.revoked,
        }


class AuthSessionStore:
    """Tracks authenticated sessions in memory."""

    def __init__(self) -> None:
        self._sessions: dict[str, AuthSession] = {}

    def create_session(
        self,
        result: AuthResult,
        ttl: float | None = None,
        now: float | None = None,
    ) -> AuthSession:
        current_time = time.time() if now is None else now
        session_ttl = result.ttl if ttl is None else ttl
        expires_at = 0.0
        if session_ttl > 0 and not math.isinf(session_ttl):
            expires_at = current_time + session_ttl
        session = AuthSession(
            session_id=generate_id("sess", 24),
            backend=result.backend,
            identity=result.identity,
            policies=list(result.policies),
            metadata=dict(result.metadata),
            ttl=session_ttl,
            created_at=current_time,
            last_active=current_time,
            expires_at=expires_at,
        )
        self._sessions[session.session_id] = session
        return session

    def lookup(self, session_id: str, now: float | None = None) -> AuthSession:
        if not session_id:
            raise AuthenticationError("session_id is required")
        session = self._sessions.get(session_id)
        if session is None:
            raise AuthenticationError("session not found")
        current_time = time.time() if now is None else now
        if not session.is_valid_at(current_time):
            raise AuthenticationError("session is expired or revoked")
        return session

    def get_session(self, session_id: str) -> AuthSession | None:
        return self._sessions.get(session_id)

    def touch_session(self, session_id: str, now: float | None = None) -> AuthSession:
        session = self.lookup(session_id, now=now)
        session.touch(now=now)
        return session

    def revoke_session(self, session_id: str) -> bool:
        session = self._sessions.get(session_id)
        if session is None:
            return False
        session.revoke()
        return True

    def list_sessions(
        self,
        identity: str | None = None,
        include_invalid: bool = False,
        now: float | None = None,
    ) -> list[AuthSession]:
        current_time = time.time() if now is None else now
        sessions = list(self._sessions.values())
        if identity is not None:
            sessions = [session for session in sessions if session.identity == identity]
        if not include_invalid:
            sessions = [session for session in sessions if session.is_valid_at(current_time)]
        return sorted(sessions, key=lambda session: session.session_id)

    def delete_session(self, session_id: str) -> bool:
        return self._sessions.pop(session_id, None) is not None


@dataclass
class MFAChallenge:
    """Single in-memory MFA challenge."""

    challenge_id: str
    identity: str
    factor: str
    code_hash: bytes = field(repr=False)
    salt: bytes = field(repr=False)
    iterations: int = field(repr=False, default=50_000)
    ttl: float = 300.0
    max_attempts: int = 3
    attempts: int = 0
    metadata: dict[str, str] = field(default_factory=dict)
    created_at: float = field(default_factory=time.time)
    verified_at: float | None = None

    @property
    def is_expired(self) -> bool:
        return self.ttl > 0 and time.time() >= self.created_at + self.ttl

    @property
    def is_verified(self) -> bool:
        return self.verified_at is not None

    def is_expired_at(self, now: float) -> bool:
        return self.ttl > 0 and now >= self.created_at + self.ttl

    def to_dict(self) -> dict[str, Any]:
        return {
            "challenge_id": self.challenge_id,
            "identity": self.identity,
            "factor": self.factor,
            "ttl": self.ttl,
            "max_attempts": self.max_attempts,
            "attempts": self.attempts,
            "metadata": dict(self.metadata),
            "created_at": self.created_at,
            "verified_at": self.verified_at,
        }


class MFAChallengeStore:
    """Creates and verifies local MFA challenges."""

    def __init__(self, iterations: int = 50_000) -> None:
        if iterations <= 0:
            raise VaultError("hash iterations must be positive")
        self._iterations = iterations
        self._challenges: dict[str, MFAChallenge] = {}

    def create_challenge(
        self,
        identity: str,
        factor: str = "code",
        code: str | None = None,
        ttl: float = 300.0,
        max_attempts: int = 3,
        metadata: dict[str, str] | None = None,
        now: float | None = None,
    ) -> MFAChallenge:
        if not identity:
            raise AuthenticationError("identity is required")
        if not factor:
            raise AuthenticationError("mfa factor is required")
        if max_attempts <= 0:
            raise VaultError("max_attempts must be positive")
        challenge_code = code or generate_id("", 8)
        salt = generate_salt()
        current_time = time.time() if now is None else now
        challenge = MFAChallenge(
            challenge_id=generate_id("mfa", 16),
            identity=identity,
            factor=factor,
            code_hash=_hash_secret(challenge_code, salt, self._iterations),
            salt=salt,
            iterations=self._iterations,
            ttl=ttl,
            max_attempts=max_attempts,
            metadata=dict(metadata or {}),
            created_at=current_time,
        )
        self._challenges[challenge.challenge_id] = challenge
        return challenge

    def issue_challenge(
        self,
        identity: str,
        factor: str = "code",
        ttl: float = 300.0,
        max_attempts: int = 3,
        metadata: dict[str, str] | None = None,
        now: float | None = None,
    ) -> tuple[MFAChallenge, str]:
        code = generate_id("", 8)
        challenge = self.create_challenge(
            identity=identity,
            factor=factor,
            code=code,
            ttl=ttl,
            max_attempts=max_attempts,
            metadata=metadata,
            now=now,
        )
        return challenge, code

    def verify_challenge(
        self,
        challenge_id: str,
        code: str,
        now: float | None = None,
    ) -> MFAChallenge:
        if not challenge_id or not code:
            raise AuthenticationError("challenge_id and code are required")
        challenge = self._challenges.get(challenge_id)
        if challenge is None:
            raise AuthenticationError("mfa challenge not found")
        current_time = time.time() if now is None else now
        if challenge.is_verified:
            raise AuthenticationError("mfa challenge already verified")
        if challenge.is_expired_at(current_time):
            raise AuthenticationError("mfa challenge expired")
        if challenge.attempts >= challenge.max_attempts:
            raise AuthenticationError("mfa challenge attempts exhausted")

        if not _verify_secret(code, challenge.salt, challenge.code_hash, challenge.iterations):
            challenge.attempts += 1
            raise AuthenticationError("invalid mfa code")

        challenge.verified_at = current_time
        return challenge

    def get_challenge(self, challenge_id: str) -> MFAChallenge | None:
        return self._challenges.get(challenge_id)

    def list_challenges(
        self,
        identity: str | None = None,
        include_expired: bool = True,
        now: float | None = None,
    ) -> list[MFAChallenge]:
        current_time = time.time() if now is None else now
        challenges = list(self._challenges.values())
        if identity is not None:
            challenges = [
                challenge for challenge in challenges
                if challenge.identity == identity
            ]
        if not include_expired:
            challenges = [
                challenge for challenge in challenges
                if not challenge.is_expired_at(current_time)
            ]
        return sorted(challenges, key=lambda challenge: challenge.challenge_id)

    def purge_expired(self, now: float | None = None) -> int:
        current_time = time.time() if now is None else now
        expired_ids = [
            challenge_id for challenge_id, challenge in self._challenges.items()
            if challenge.is_expired_at(current_time)
        ]
        for challenge_id in expired_ids:
            self._challenges.pop(challenge_id, None)
        return len(expired_ids)


@dataclass
class AuthEvent:
    """Authentication event log entry."""

    event_id: str
    backend: str
    identity: str = ""
    event_type: str = "authenticate"
    success: bool = True
    timestamp: float = field(default_factory=time.time)
    metadata: dict[str, Any] = field(default_factory=dict)

    def to_dict(self) -> dict[str, Any]:
        return {
            "event_id": self.event_id,
            "backend": self.backend,
            "identity": self.identity,
            "event_type": self.event_type,
            "success": self.success,
            "timestamp": self.timestamp,
            "metadata": dict(self.metadata),
        }


class AuthEventLogger:
    """Bounded in-memory auth event logger."""

    def __init__(self, max_entries: int = 10000) -> None:
        if max_entries <= 0:
            raise VaultError("max_entries must be positive")
        self._max_entries = max_entries
        self._events: list[AuthEvent] = []

    def log(
        self,
        backend: str,
        identity: str = "",
        success: bool = True,
        event_type: str = "authenticate",
        metadata: dict[str, Any] | None = None,
    ) -> AuthEvent:
        if not backend:
            raise AuthenticationError("backend is required")
        event = AuthEvent(
            event_id=generate_id("auth", 16),
            backend=backend,
            identity=identity,
            event_type=event_type,
            success=success,
            metadata=dict(metadata or {}),
        )
        if len(self._events) >= self._max_entries:
            self._events.pop(0)
        self._events.append(event)
        return event

    def list_events(
        self,
        backend: str | None = None,
        identity: str | None = None,
        success: bool | None = None,
        event_type: str | None = None,
        since: float = 0.0,
    ) -> list[AuthEvent]:
        events = self._events
        if backend is not None:
            events = [event for event in events if event.backend == backend]
        if identity is not None:
            events = [event for event in events if event.identity == identity]
        if success is not None:
            events = [event for event in events if event.success == success]
        if event_type is not None:
            events = [event for event in events if event.event_type == event_type]
        if since:
            events = [event for event in events if event.timestamp >= since]
        return list(events)

    @property
    def total_events(self) -> int:
        return len(self._events)

    def clear(self) -> None:
        self._events.clear()


@dataclass
class AuthConfigValidationResult:
    """Validation result for auth configuration dictionaries."""

    errors: list[str] = field(default_factory=list)
    warnings: list[str] = field(default_factory=list)

    @property
    def valid(self) -> bool:
        return not self.errors

    def add_error(self, message: str) -> None:
        self.errors.append(message)

    def add_warning(self, message: str) -> None:
        self.warnings.append(message)

    def merge(self, other: AuthConfigValidationResult) -> None:
        self.errors.extend(other.errors)
        self.warnings.extend(other.warnings)

    def to_dict(self) -> dict[str, Any]:
        return {
            "valid": self.valid,
            "errors": list(self.errors),
            "warnings": list(self.warnings),
        }


class AuthConfigValidator:
    """Validates lightweight auth backend configuration dictionaries."""

    SUPPORTED_BACKENDS = {"userpass", "approle", "cert", "token"}

    @classmethod
    def validate_backend(
        cls,
        backend_name: str,
        config: dict[str, Any],
    ) -> AuthConfigValidationResult:
        result = AuthConfigValidationResult()
        if backend_name not in cls.SUPPORTED_BACKENDS:
            result.add_error(f"unsupported auth backend: {backend_name}")
        if not isinstance(config, dict):
            result.add_error("backend config must be a dictionary")
            return result

        enabled = config.get("enabled")
        if enabled is not None and not isinstance(enabled, bool):
            result.add_error("enabled must be a boolean")

        ttl = config.get("ttl", config.get("token_ttl"))
        if ttl is not None and not _is_non_negative_number(ttl):
            result.add_error("ttl must be a non-negative number")

        if backend_name == "userpass":
            cls._validate_userpass(config, result)
        elif backend_name == "approle":
            cls._validate_approle(config, result)
        elif backend_name == "cert":
            cls._validate_cert(config, result)
        elif backend_name == "token" and config.get("allow_accessor_login") is False:
            result.add_warning("token backend will only accept token IDs")
        return result

    @classmethod
    def validate_manager_config(cls, config: dict[str, Any]) -> AuthConfigValidationResult:
        result = AuthConfigValidationResult()
        if not isinstance(config, dict):
            result.add_error("auth config must be a dictionary")
            return result
        backends = config.get("backends", {})
        if not isinstance(backends, dict):
            result.add_error("backends must be a dictionary")
            return result
        if not backends:
            result.add_warning("no auth backends configured")
        for backend_name, backend_config in backends.items():
            result.merge(cls.validate_backend(backend_name, backend_config))
        return result

    @classmethod
    def require_valid_backend(cls, backend_name: str, config: dict[str, Any]) -> None:
        result = cls.validate_backend(backend_name, config)
        if not result.valid:
            raise AuthenticationError(
                "invalid auth backend configuration",
                details=result.to_dict(),
            )

    @staticmethod
    def _validate_userpass(
        config: dict[str, Any],
        result: AuthConfigValidationResult,
    ) -> None:
        min_password_length = config.get("min_password_length")
        if min_password_length is not None:
            if not isinstance(min_password_length, int) or min_password_length <= 0:
                result.add_error("min_password_length must be a positive integer")
            elif min_password_length < 8:
                result.add_warning("min_password_length below 8 is weak")
        iterations = config.get("password_hash_iterations")
        if iterations is not None and (not isinstance(iterations, int) or iterations <= 0):
            result.add_error("password_hash_iterations must be a positive integer")

    @staticmethod
    def _validate_approle(
        config: dict[str, Any],
        result: AuthConfigValidationResult,
    ) -> None:
        secret_id_ttl = config.get("secret_id_ttl")
        if secret_id_ttl is not None and not _is_non_negative_number(secret_id_ttl):
            result.add_error("secret_id_ttl must be a non-negative number")
        secret_id_num_uses = config.get("secret_id_num_uses")
        if secret_id_num_uses is not None:
            if not isinstance(secret_id_num_uses, int) or secret_id_num_uses < 0:
                result.add_error("secret_id_num_uses must be a non-negative integer")

    @staticmethod
    def _validate_cert(
        config: dict[str, Any],
        result: AuthConfigValidationResult,
    ) -> None:
        fingerprints = config.get("fingerprints")
        if fingerprints is not None:
            if not isinstance(fingerprints, list):
                result.add_error("fingerprints must be a list")
            elif any(not isinstance(item, str) or not item for item in fingerprints):
                result.add_error("fingerprints must contain non-empty strings")


def validate_auth_config(config: dict[str, Any]) -> AuthConfigValidationResult:
    """Validate a manager-style auth configuration dictionary."""
    return AuthConfigValidator.validate_manager_config(config)


def _is_non_negative_number(value: Any) -> bool:
    return isinstance(value, (int, float)) and not isinstance(value, bool) and value >= 0

